        Console.WriteLine($"Code: {warning.Code} | {warning.Message}");
        warnCount++;
    }
});

// Check for failed tasks
Console.WriteLine("\n=== FAILED TARGETS/TASKS ===");
build.VisitAllChildren<Target>(target => {
    if (!target.Succeeded) {
        Console.WriteLine($"Failed target: {target.Name} in {target.Project?.ProjectFile}");
    }
});

build.VisitAllChildren<Task>(task => {
    if (task.Name != null) {
        // Check children for errors
        foreach (var child in task.Children) {
            if (child is Error) {
                Console.WriteLine($"Failed task: {task.Name} in target context");
            }
        }
    }
});
